    pattern: 'HashMap Lookup',
    recognition: ['Need fast lookup', 'Pair search in array', 'Target sum problem'],
    approach: 'Iterate through array once. For each element, calculate complement (target - current). If complement exists in hashmap, return indices. Otherwise, store current element and its index in hashmap.',
    approach_steps: [
      'Create an empty hash map to store numbers and their indices',
      'Iterate through array, calculate complement = target - current',
      'Check if complement exists in hash map',
      'If found, return indices; else store current and continue'
    ],
    approach_diagram: 'Input [2,7,11,15] target=9\n  i=0: 2 -> complement=7 -> not in map -> store {2:0}\n  i=1: 7 -> complement=2 -> FOUND! -> return [0,1]\n  Output: [0,1]',
    complexity: { time: 'O(n)', space: 'O(n)' },
    template: {
      javascript: `function twoSum(nums: number[], target: number): number[] {
  const map = new Map<number, number>();
  for (let i = 0; i < nums.length; i++) {
    const complement = target - nums[i];
    if (map.has(complement)) {
      return [map.get(complement)!, i];
    }
    map.set(nums[i], i);
  }
  return [];
}`,
      python: `def two_sum(nums, target):
    seen = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return [seen[complement], i]
        seen[num] = i
    return []`,
      java: `class Solution {
    public int[] twoSum(int[] nums, int target) {
        Map<Integer, Integer> map = new HashMap<>();
        for (int i = 0; i < nums.length; i++) {
            int complement = target - nums[i];
            if (map.containsKey(complement))
                return new int[]{map.get(complement), i};
            map.put(nums[i], i);
        }
        return new int[]{};
    }
}`,
      cpp: `class Solution {
public:
    vector<int> twoSum(vector<int>& nums, int target) {
        unordered_map<int, int> map;
        for (int i = 0; i < nums.size(); i++) {
            int complement = target - nums[i];
            if (map.count(complement))
                return {map[complement], i};
            map[nums[i]] = i;
        }
        return {};
    }
};`,
    },
