      javascript: `function ladderLength(beginWord: string, endWord: string, wordList: string[]): number {
  const wordSet = new Set(wordList);
  if (!wordSet.has(endWord)) return 0;
  const queue: [string, number][] = [[beginWord, 1]];
  const visited = new Set<string>([beginWord]);
  while (queue.length) {
    const [word, dist] = queue.shift()!;
    if (word === endWord) return dist;
    for (let i = 0; i < word.length; i++) {
      for (let c = 97; c <= 122; c++) {
        const newWord = word.slice(0, i) + String.fromCharCode(c) + word.slice(i + 1);
        if (wordSet.has(newWord) && !visited.has(newWord)) {
          visited.add(newWord);
          queue.push([newWord, dist + 1]);
        }
      }
    }
  }
  return 0;
}`,
      python: `from collections import deque
def ladder_length(begin_word, end_word, word_list):
    word_set = set(word_list)
    if end_word not in word_set: return 0
    q = deque([(begin_word, 1)])
    visited = {begin_word}
    while q:
        word, length = q.popleft()
        if word == end_word: return length
        for i in range(len(word)):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                nxt = word[:i] + c + word[i+1:]
                if nxt in word_set and nxt not in visited:
                    visited.add(nxt)
                    q.append((nxt, length + 1))
    return 0`,
      java: `class Solution {
    public int ladderLength(String beginWord, String endWord, List<String> wordList) {
        Set<String> wordSet = new HashSet<>(wordList);
        if (!wordSet.contains(endWord)) return 0;
        Queue<String> q = new LinkedList<>();
        q.offer(beginWord);
        int len = 1;
        while (!q.isEmpty()) {
            for (int i = q.size(); i > 0; i--) {
                char[] word = q.poll().toCharArray();
                for (int j = 0; j < word.length; j++) {
                    char orig = word[j];
                    for (char c = 'a'; c <= 'z'; c++) {
                        word[j] = c;
                        String nxt = new String(word);
                        if (nxt.equals(endWord)) return len + 1;
                        if (wordSet.contains(nxt)) { wordSet.remove(nxt); q.offer(nxt); }
                    }
                    word[j] = orig;
                }
            }
            len++;
        }
        return 0;
    }
}`,
      cpp: `class Solution {
public:
    int ladderLength(string beginWord, string endWord, vector<string>& wordList) {
        unordered_set<string> wordSet(wordList.begin(), wordList.end());
        if (!wordSet.count(endWord)) return 0;
        queue<string> q;
        q.push(beginWord);
        int len = 1;
        while (!q.empty()) {
            for (int i = q.size(); i > 0; i--) {
                string word = q.front(); q.pop();
                for (int j = 0; j < word.size(); j++) {
                    char orig = word[j];
                    for (char c = 'a'; c <= 'z'; c++) {
                        word[j] = c;
                        if (word == endWord) return len + 1;
                        if (wordSet.count(word)) { wordSet.erase(word); q.push(word); }
                    }
                    word[j] = orig;
                }
            }
            len++;
        }
        return 0;
    }
};`,
